// Generates lib/blog.generated.ts by scanning content/reading-room/*.tsx.
//
// Why this exists: the Reading Room registry used to be a hand-maintained list
// of imports + array entries in lib/blog.ts. Every new post touched those same
// two spots, so parallel branches collided on merge. Auto-discovery makes each
// post a drop-in file — content/reading-room/*.tsx is the single source of
// truth, and the registry is derived from it at dev/build time.
//
// The output is gitignored on purpose (see .gitignore): it's a pure build
// artifact. It's regenerated by the `predev` / `prebuild` npm hooks (and the
// `gen:blog` script), so it always reflects whatever post files are present.

import { readdirSync, writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const root = join(dirname(fileURLToPath(import.meta.url)), "..");
const contentDir = join(root, "content", "reading-room");
const outFile = join(root, "lib", "blog.generated.ts");

const files = readdirSync(contentDir)
  .filter((f) => f.endsWith(".tsx"))
  .map((f) => f.replace(/\.tsx$/, ""))
  // Stable, deterministic order (display order is decided at runtime by date).
  .sort();

const lines = [
  "// AUTO-GENERATED by scripts/generate-blog-registry.mjs — DO NOT EDIT.",
  "// Regenerated on every dev/build. Gitignored: content/reading-room/*.tsx is",
  "// the single source of truth, so new posts are drop-in files with no shared",
  "// registry edit (and therefore no merge conflicts between parallel branches).",
  'import type { BlogPost } from "./blog";',
];

files.forEach((slugFile, i) => {
  lines.push(
    `import { meta as m${i}, default as B${i} } from "@/content/reading-room/${slugFile}";`,
  );
});

lines.push("");
lines.push("export const registry: BlogPost[] = [");
files.forEach((_, i) => {
  lines.push(`  { ...m${i}, Body: B${i} },`);
});
lines.push("];");
lines.push("");

writeFileSync(outFile, lines.join("\n"));
console.log(
  `[generate-blog-registry] wrote ${files.length} posts → lib/blog.generated.ts`,
);
